package no.bbs.trust.ts.idp.nemid.verify;

import static org.junit.Assert.assertTrue;

import java.io.UnsupportedEncodingException;
import java.security.Security;
import no.bbs.trust.common.basics.exceptions.StatusCodeException;

import org.bouncycastle.jce.provider.BouncyCastleProvider;
import org.bouncycastle.util.encoders.Base64;
import org.junit.Test;
import org.openoces.ooapi.environment.Environments;


public class SignatureVerifierTester {
	@Test
	public void test_handleVerifyClientSignatureData_validinput() throws StatusCodeException, UnsupportedEncodingException {
		Environments.setEnvironments(Environments.Environment.OCESII_DANID_ENV_PREPROD, Environments.Environment.OCESI_DANID_ENV_SYSTEMTEST);
		
		Security.addProvider(new BouncyCastleProvider());
			
		VerifyClientSignatureData data = new VerifyClientSignatureData();
		data.setChallenge("challenge");
		data.setResult(new String(Base64.encode("ok".getBytes())));
		data.setSignature("");
		data.setB64Document("This is a document");
		
		SignatureVerifier signatureVerifier = new SignatureVerifier(data);
		signatureVerifier.handleVerifyClientSignatureData();
		assertTrue(signatureVerifier.isValidatedOK());

	}
}
